ll n, m, r, k;
ll cal(ll x, ll y) {
	ll tmpx = (max(1ll, min(n, x + (r - 1)) - (r - 1))) - max(1ll, x - (r - 1)) + 1;
	ll tmpy = (max(1ll, min(m, y + (r - 1)) - (r - 1))) - max(1ll, y - (r - 1)) + 1;
	return tmpx * tmpy;
}
struct node {
	ll x, y, res;
	node(ll x, ll y) :x(x), y(y), res(cal(x, y)) {}
	bool operator<(const node& a)const {
		return res < a.res;
	}
};
void solve(int CASE)
{
	cin >> n >> m >> r >> k;
	// x,y
	// x: max(1, x - (r - 1)) - (min(n, x + (r - 1)) - (r - 1))
	// y: max(1, y - (r - 1)) - (min(m, y + (r - 1)) - (r - 1))
	ll sx = (n + 1) / 2, sy = (m + 1) / 2;
	var Q = priority_queue<node>();
	var vis = set<pii>();
	ll ans = 0, tot = (n - r + 1) * (m - r + 1);
	Q.push({ sx,sy });
	while (Q.size() and k > 0) {
		var[x, y, res] = Q.top();
		Q.pop();
		if (vis.count({ x,y }))continue;
		vis.insert({ x,y });
		k--;
		ans += res;
		fa(i, 0, 3) {
			int nx = x + dx[i];
			int ny = y + dy[i];
			if (nx < 1 or nx > n or ny < 1 or ny > m)continue;
			Q.push({ nx,ny });
		}
	}
	cout << fixed << setprecision(12) << ans * 1.0 / tot << endl;
	return;
}
